import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class FileRead {
    public static void main(String[] args) {
        String fileName = args[0]; // Assuming user input is passed as a command line argument

        try {
            File file = new File("data/" + fileName); // User input is directly concatenated with the base directory
            FileInputStream fis = new FileInputStream(file);

            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }

            fis.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

